// src/services/notificationService.js
import { useNotificationsStore } from '@/stores/notifications';

export const notificationService = {
    // Системное уведомление
    system(title, content, type = 'info', autoclose = 5) {
        const store = useNotificationsStore();
        return store.add({
            app: 'system',
            title,
            content,
            type,
            autoclose
        });
    },

    // От приложения
    fromApp(appId, appName, title, content, type = 'info', actions = [], autoclose = 5) {
        const store = useNotificationsStore();
        return store.add({
            app: appId,
            title: `[${appName}] ${title}`,
            content,
            type,
            actions,
            autoclose
        });
    },

    // Короткие методы
    success(title, content, autoclose = 5) {
        return this.system(title, content, 'success', autoclose);
    },

    error(title, content, autoclose = 10) {
        return this.system(title, content, 'error', autoclose);
    },

    warning(title, content, autoclose = 5) {
        return this.system(title, content, 'warning', autoclose);
    },

    info(title, content, autoclose = 5) {
        return this.system(title, content, 'info', autoclose);
    }
};
